teiHeader.profileDesc:
{% for x in objects %}{% if x.lb_id %}

            {% if x.metadata_notes %}

               {% for meta in x.metadata_notes %}
               {{ meta.text }}
               {% endfor %}

            {% endif %}

            {% for sender in x.sender %}
               {{ sender.value }}
           {% if x.place_of_writing or x.placename_written %}
               {% for place in x.place_of_writing %}
               {{ place.label }}
               {% endfor %}
               {% if x.placename_written %}
               {{ x.placename_written }}
               {% endif %}
            {% endif %}
            {% endfor %}
            {% if x.written_date or x.not_before or x.not_after %}
               {% if x.written_date %}{{ x.written_date }}{% else %}{{ x.not_before or x.not_after }}{% endif %}{% if x.date_note %}
               {{ x.date_note }}{% endif %}
            {% endif %}


            {% for receiver in x.receiver %}

               {{ receiver.label }}

            {% endfor %}
            {% if x.destination %}

               {% for place in x.destination %}
               {{ place.value }}
               {% endfor %}

            {% endif %}
            {% if x.received_place %}
               {% for place in x.received_place %}
               {{ place.label }}
               {% endfor %}
            {% endif %}
            {% if x.received_date %}
               {{ x.received_date }}
            {% endif %}


         {% endif %}{% endfor %}
